console-logger-class.body:
import com.nomagic.magicdraw.core.Application
import com.nomagic.magicdraw.core.GUILog
import org.apache.log4j.Logger
import java.io.StringWriter
import java.io.PrintWriter

/**
 * Robust logger for Cameo/MagicDraw Groovy scripts.
 * info/debug -> log4j only (reduces GUI console clutter)
 * warn/error -> log4j + GUI console (surface real problems)
 * STRICT RULE: never swallow exceptions — always use the (msg, Throwable) overload.
 */
class SysMLv2Logger {
    private final Logger log
    private final GUILog gl

    SysMLv2Logger(Class<?> clazz) {
        this.log = Logger.getLogger(clazz)
        this.gl = Application.getInstance().getGUILog()
    }

    SysMLv2Logger(String name) {
        this.log = Logger.getLogger(name)
        this.gl = Application.getInstance().getGUILog()
    }

    void info(String message)  { log.info(message) }
    void debug(String message) { log.debug(message) }

    void warn(String message) {
        log.warn(message)
        if (gl != null) gl.log('[WARNING] ' + message)
    }

    void warn(String message, Throwable t) {
        log.warn(message, t)
        if (gl != null) gl.log('[WARNING] ' + message + '\n' + stackTrace(t))
        else { System.err.println('[WARNING] ' + message); t.printStackTrace(System.err) }
    }

    void error(String message) {
        log.error(message)
        if (gl != null) gl.log('[ERROR] ' + message)
        else System.err.println('[ERROR] ' + message)
    }

    void error(String message, Throwable t) {
        log.error(message, t)
        if (gl != null) gl.log('[ERROR] ' + message + '\n' + stackTrace(t))
        else { System.err.println('[ERROR] ' + message); t.printStackTrace(System.err) }
    }

    private String stackTrace(Throwable t) {
        if (t == null) return ''
        def sw = new StringWriter()
        t.printStackTrace(new PrintWriter(sw))
        return sw.toString()
    }
}

