// Load a companion class (e.g. SysMLv2Logger) next to the current script.
// Use '+' concatenation for paths — avoid GStrings at Cameo API boundaries.
String scriptDir = 'E:\\_Documents\\git\\TutorialForCatiaMagicApiMCP\\scripts'
File loggerFile = new File(scriptDir, 'SysMLv2Logger.groovy')

// The parent classloader MUST be getClass().getClassLoader() (the Cameo one),
// otherwise com.nomagic.* imports in the loaded class won't resolve.
def LoggerClass = new GroovyClassLoader(getClass().getClassLoader()).parseClass(loggerFile)
def logger = LoggerClass.newInstance('MyScript')

logger-usage.body:
// Assumes SysMLv2Logger was loaded via the 'script-load-groovy' snippet.
def logger = LoggerClass.newInstance('MyFeatureName')

try {
    def project = com.nomagic.magicdraw.core.Application.getInstance().getProject()
    if (project == null) {
        logger.error('No active MagicDraw project.')
        return
    }

    logger.info('Starting work on: ' + project.getName())
    // ... your work here ...
    logger.info('Done.')
} catch (Throwable t) {
    // NEVER swallow. Always pass the Throwable so the stack trace is preserved.
    logger.error('Critical failure during script execution', t)
}

