// The File is cleared on the first call to the logger's constructor, so
// the file always contains only the CURRENT run's output. Put the file
// under the project's logs/ dir so it is not lost across Cameo restarts.
import java.io.File

File runLog = new File(
    'E:\\_Documents\\git\\TutorialForCatiaMagicApiMCP\\logs',
    'MyScript.log'
)
def logger = LoggerClass.newInstance('MyScript', runLog)
logger.info('=== MyScript run started ===')
try {
    // ... work ...
    logger.info('Done.')
} catch (Throwable t) {
    logger.error('MyScript failed', t)   // appends to runLog with stack trace
}

