import com.nomagic.magicdraw.commandline.ProjectCommandLine;
import com.nomagic.magicdraw.core.Project;
import com.nomagic.magicdraw.utils.MDLog;

import java.util.Properties;

public class MyBatchRunner extends ProjectCommandLine {

    public static void main(String[] args) throws InstantiationException {
        new MyBatchRunner().launch(args);
    }

    @Override
    protected byte execute(Properties props, Project project) {
        if (project == null) {
            printToCommandLineConsole("Project was not loaded.");
            return -1;
        }
        try {
            // ... do the work; NEVER call System.exit ...
            return 0;
        } catch (Throwable t) {
            MDLog.getGeneralLog().error(t.getMessage(), t);
            printToCommandLineConsole("FAILED: " + t.getMessage());
            return -1;
        }
    }

    @Override
    protected void parseArguments(String[] args) {
        // Parse your CLI args here; set fields as needed.
    }
}
